import React from 'react'
import { IconButton, Theme, useMenuOverlay } from '@fs/zion-ui'
import { MenuMore } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import ChatChannelMenu from '../chat-window/chat-window-chats/ChatChannelMenu'
import { useCurrentChannel } from '../hooks/channelHooks'
import { useChatState } from '../providers/ChatStateProvider'

export default function ChatHeaderMenu() {
  const [t] = useTranslation()
  const menuOverlay = useMenuOverlay()
  const channel = useCurrentChannel()
  const { darkMode } = useChatState()

  return (
    <>
      <IconButton
        Icon={MenuMore}
        aria-label={t('chat.menu.aria-label', 'Chat Menu')}
        data-testid="chat-channel-menu"
        {...menuOverlay.menuButtonProps}
      />

      <Theme theme={darkMode ? 'night' : 'day'} transparent>
        <ChatChannelMenu menuOverlay={menuOverlay} channel={channel} isHeader />
      </Theme>
    </>
  )
}
