import React from 'react'
import { useTranslation } from 'react-i18next'
import { Ellipsis, Row } from '@fs/zion-ui'
import BackButton from '../chat-buttons/BackButton'
import { useChatState } from '../providers/ChatStateProvider'
import ChatHeaderMenu from './ChatHeaderMenu'
import ChatHeaderBlock from './ChatHeaderBlock'
import { useCurrentChannel } from '../hooks/channelHooks'
import useChatHeaderBlockInfo from '../hooks/useChatHeaderBlockInfo'

const getHeaderText = (t, matchBlockedUsers, isDetails, isGroup, isCreate, matchHiddenChats, createText) => {
  let headerText
  if (matchBlockedUsers) {
    headerText = t('chat.blocked-users.heading', 'Blocked Users')
  }
  if (isDetails && isGroup) {
    headerText = t('chat.chat-details.header', 'Chat Details')
  }
  if (isCreate) {
    headerText = createText
  }
  if (matchHiddenChats) {
    headerText = t('chat.hidden-chats.heading', 'Hidden Chat')
  }
  return headerText
}

export default function ChatHeader() {
  const [t] = useTranslation()
  const { connectError, client, parentMessage } = useChatState()
  const channel = useCurrentChannel()
  const {
    isGroup,
    isDetails,
    matchBlockedUsers,
    matchCreateVendor,
    isCreate,
    displayPersonHeader,
    displayGroupHeader,
    createText,
    matchHiddenChats,
  } = useChatHeaderBlockInfo(channel, client?.userID)
  if (connectError) return null
  const headerText = getHeaderText(t, matchBlockedUsers, isDetails, isGroup, isCreate, matchHiddenChats, createText)

  return (
    <Row alignY="middle" gutters={displayPersonHeader || displayGroupHeader ? 'xs' : 'nano'} guttersY="none">
      {!matchCreateVendor && <BackButton inHeader noShrinkX />}
      <ChatHeaderBlock
        growX
        parentMessage={parentMessage}
        displayPersonHeader={displayPersonHeader}
        displayGroupHeader={displayGroupHeader}
        channel={channel}
      />
      {headerText && <Ellipsis growX>{headerText}</Ellipsis>}
      <ChatHeaderMenu noShrinkX />
    </Row>
  )
}
