import { useTranslation } from 'react-i18next'
import { useHistory, useRouteMatch } from '@fs/zion-router'
import { isGroupChannel } from '../services/fsChat/fsChatService'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'

export default function useChatHeaderBlockInfo(channel, myUserId) {
  const [t] = useTranslation()
  const history = useHistory()
  // useLocation is used here instead of useParams, because some parts of the code may not have access to any params (left panel, header, etc)
  const isGroup = isGroupChannel({ channel, excludeUserId: myUserId })
  const isDetails = history?.location?.pathname?.endsWith('/details')
  const matchCreateGroup = useRouteMatch(buildChatRoute(CHAT_ROUTE_KEY.CREATE_PUBLIC_CHAT))
  const matchCreateVendor = useRouteMatch(buildChatRoute(CHAT_ROUTE_KEY.CREATE_VENDOR_CHAT))
  const matchBlockedUsers = useRouteMatch(buildChatRoute(CHAT_ROUTE_KEY.BLOCKED))
  const matchHiddenChats = useRouteMatch(buildChatRoute(CHAT_ROUTE_KEY.HIDDEN))
  const isCreate = history?.location?.pathname?.includes('/chat-create')
  const displayPersonHeader = !isGroup && !isCreate && !matchBlockedUsers && !matchHiddenChats
  const displayGroupHeader = isGroup && !isCreate && !isDetails
  let createText
  if (matchCreateGroup) {
    createText = t('chat.new-group.header', 'Create New Chat')
  } else if (matchCreateVendor) {
    createText = t('chat.new-vendor.header', 'Creating Chat')
  } else {
    createText = t('chat.new-chat.header', 'New Chat')
  }

  return {
    isGroup,
    isDetails,
    matchCreateGroup,
    matchCreateVendor,
    isCreate,
    matchBlockedUsers,
    displayPersonHeader,
    displayGroupHeader,
    createText,
    matchHiddenChats,
  }
}
